import { useMemo } from "react";

interface DataItem {
  label: string;
  code?: string;
  value1: number;
  value2: number;
  difference: number;
  date: string;
}

interface Filter {
  limit: number;
  date: number | string;
  criteria: string;
  sortingDir: "asc" | "desc";
}

export const useGapChartData = (
  dataSet: DataItem[],
  filter: Filter | undefined,
  disabledItems: string[],
  tickValues?: Array<number | Date>
) => {
  // Calculate differences and filter data
  const processedDataSet = useMemo(() => {
    const dataWithDifference = dataSet.map(item => ({
      ...item,
      difference: item.difference != null ? item.difference : item.value1 - item.value2,
    }));

    if (!filter) {
      return dataWithDifference.filter(d => !disabledItems.includes(d.label));
    }

    // Filter by date if specified
    const dateFilteredData = filter.date
      ? dataWithDifference.filter(d => d.date === filter.date)
      : dataWithDifference;

    // Sort by the specified criteria field
    const sortedData = dateFilteredData.slice().sort((a, b) => {
      const aValue = a[filter.criteria as keyof DataItem] as number;
      const bValue = b[filter.criteria as keyof DataItem] as number;
      const diff = filter.sortingDir === "desc" ? bValue - aValue : aValue - bValue;
      return diff;
    });

    // Apply limit and remove disabled items
    return sortedData.slice(0, filter.limit).filter(d => !disabledItems.includes(d.label));
  }, [dataSet, filter, disabledItems]);

  // Get unique labels for y-axis (include all original labels for color generation)
  const allLabels = useMemo(() => {
    const dataWithDifference = dataSet.map(item => ({
      ...item,
      difference: item.value1 - item.value2,
    }));

    if (!filter) {
      return dataWithDifference.map(d => d.label);
    }

    // Filter by date if specified (but don't exclude disabled items for color generation)
    const dateFilteredData = filter.date
      ? dataWithDifference.filter(d => d.date === filter.date)
      : dataWithDifference;

    // Sort by the specified criteria field
    const sortedData = dateFilteredData.slice().sort((a, b) => {
      const aValue = a[filter.criteria as keyof DataItem] as number;
      const bValue = b[filter.criteria as keyof DataItem] as number;
      const diff = filter.sortingDir === "desc" ? bValue - aValue : aValue - bValue;
      return diff;
    });

    // Apply limit but keep all labels (including disabled ones) for color generation
    return sortedData.slice(0, filter.limit).map(d => d.label);
  }, [dataSet, filter]);

  // For rendering, use processed dataset (excluding disabled items)
  const yAxisDomain = useMemo(() => processedDataSet.map(d => d.label), [processedDataSet]);

  // Calculate x-axis domain (min and max values)
  const xAxisDomain = useMemo((): [number, number] => {
    if (processedDataSet.length === 0) return [0, 0];
    if (
      tickValues &&
      tickValues.length > 1 &&
      typeof tickValues[0] === "number" &&
      typeof tickValues[tickValues.length - 1] === "number"
    ) {
      return [tickValues[0], tickValues[tickValues.length - 1] as number];
    }

    const allValues = processedDataSet.flatMap(d => [d.value1, d.value2]);
    const dataMin = Math.min(...allValues);
    const dataMax = Math.max(...allValues);

    // If all values are positive, start at 0. If there are negative values, include them.
    const min = dataMin < 0 ? dataMin * 1.1 : 0; // Start at 0 for positive data
    const max = dataMax * 1.1; // Add 10% padding to the maximum

    return [min, max];
  }, [processedDataSet, tickValues]);

  return {
    processedDataSet,
    yAxisDomain,
    xAxisDomain,
    allLabels, // Include all labels for color generation
  };
};
